import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { getSocket } from '../socket';
import { showPopunder } from '../utils/adUtils';
import VideoCall from '../components/VideoCall';
import './RandomMatchPage.css';

const RandomMatchPage = () => {
  const { user } = useAuth();
  const [status, setStatus] = useState('idle'); // idle, searching, matched
  const [partner, setPartner] = useState(null);
  const [roomId, setRoomId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isPartnerTyping, setIsPartnerTyping] = useState(false);
  const [showVideoCall, setShowVideoCall] = useState(false);
  const messagesEndRef = useRef(null);
  const typingTimeout = useRef(null);

  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;

    socket.on('searching', (data) => {
      setStatus('searching');
      console.log(data.message);
    });

    socket.on('match_found', (data) => {
      setStatus('matched');
      setPartner(data.partner);
      setRoomId(data.roomId);
      setMessages([]);
      console.log('Match found:', data.partner.nickname);
    });

    socket.on('match_message_received', (data) => {
      setMessages(prev => [...prev, {
        from: data.from,
        fromNickname: data.fromNickname,
        text: data.message,
        timestamp: data.timestamp,
        isMine: false
      }]);
    });

    socket.on('match_partner_typing', () => {
      setIsPartnerTyping(true);
    });

    socket.on('match_partner_stop_typing', () => {
      setIsPartnerTyping(false);
    });

    socket.on('match_ended', (data) => {
      setStatus('idle');
      setPartner(null);
      setRoomId(null);
      setMessages([]);
      alert(data.message);
    });

    socket.on('search_cancelled', () => {
      setStatus('idle');
    });

    return () => {
      socket.off('searching');
      socket.off('match_found');
      socket.off('match_message_received');
      socket.off('match_partner_typing');
      socket.off('match_partner_stop_typing');
      socket.off('match_ended');
      socket.off('search_cancelled');
    };
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const findMatch = () => {
    const socket = getSocket();
    if (socket && user) {
      // Show popunder ad on user interaction
      showPopunder();

      socket.emit('find_match', {
        userId: user._id,
        gender: user.gender,
        nickname: user.nickname
      });
      setStatus('searching');
    }
  };

  const cancelSearch = () => {
    const socket = getSocket();
    if (socket && user) {
      socket.emit('cancel_search', user._id);
      setStatus('idle');
    }
  };

  const endMatch = () => {
    const socket = getSocket();
    if (socket && roomId) {
      socket.emit('end_match', { roomId, userId: user._id });
      setStatus('idle');
      setPartner(null);
      setRoomId(null);
      setMessages([]);
    }
  };

  const sendMessage = (e) => {
    e.preventDefault();
    if (!inputMessage.trim() || !roomId) return;

    const socket = getSocket();
    if (socket) {
      socket.emit('match_message', {
        roomId,
        message: inputMessage.trim(),
        from: user._id,
        fromNickname: user.nickname
      });

      setMessages(prev => [...prev, {
        from: user._id,
        fromNickname: user.nickname,
        text: inputMessage.trim(),
        timestamp: new Date(),
        isMine: true
      }]);

      setInputMessage('');
      socket.emit('match_stop_typing', { roomId, from: user._id });
    }
  };

  const handleTyping = (e) => {
    setInputMessage(e.target.value);
    const socket = getSocket();

    if (socket && roomId) {
      socket.emit('match_typing', { roomId, from: user._id });

      if (typingTimeout.current) {
        clearTimeout(typingTimeout.current);
      }

      typingTimeout.current = setTimeout(() => {
        socket.emit('match_stop_typing', { roomId, from: user._id });
      }, 1000);
    }
  };

  return (
    <div className="random-match-page">
      {status === 'idle' && (
        <div className="match-idle">
          <div className="match-card">
            <h1>🎲 Random Match</h1>
            <p className="match-description">
              Get paired with a random {user?.gender === 'Male' ? 'female' : 'male'} user for a chat!
            </p>
            <div className="user-preview">
              <div className={`avatar ${user?.gender?.toLowerCase()}`}>
                {user?.nickname?.charAt(0).toUpperCase()}
              </div>
              <span>{user?.nickname}</span>
              <span className={`gender-tag ${user?.gender?.toLowerCase()}`}>
                {user?.gender === 'Male' ? '👨' : '👩'} {user?.gender}
              </span>
            </div>
            <button className="find-match-btn" onClick={findMatch}>
              🔍 Find Match
            </button>
          </div>
        </div>
      )}

      {status === 'searching' && (
        <div className="match-searching">
          <div className="searching-card">
            <div className="searching-animation">
              <div className="pulse-ring"></div>
              <div className="pulse-ring"></div>
              <div className="pulse-ring"></div>
              <div className={`searching-avatar ${user?.gender?.toLowerCase()}`}>
                {user?.nickname?.charAt(0).toUpperCase()}
              </div>
            </div>
            <h2>Looking for a match...</h2>
            <p>Please wait while we find you a {user?.gender === 'Male' ? 'female' : 'male'} partner</p>
            <button className="cancel-btn" onClick={cancelSearch}>
              ✕ Cancel
            </button>
          </div>
        </div>
      )}

      {status === 'matched' && partner && (
        <div className="match-chat">
          <div className="match-chat-header">
            <div className="partner-info">
              <div className={`partner-avatar ${partner.gender?.toLowerCase()}`}>
                {partner.nickname?.charAt(0).toUpperCase()}
              </div>
              <div>
                <h3>{partner.nickname}</h3>
                <span className={`gender-badge ${partner.gender?.toLowerCase()}`}>
                  {partner.gender === 'Male' ? '👨' : '👩'} {partner.gender}
                </span>
              </div>
            </div>
            <div className="header-actions">
              <button 
                className="video-call-btn" 
                onClick={() => setShowVideoCall(!showVideoCall)}
                title={showVideoCall ? 'Hide Video' : 'Start Video Call'}
              >
                📹 {showVideoCall ? 'Hide' : 'Video'}
              </button>
              <button className="end-match-btn" onClick={endMatch}>
                End Chat
              </button>
            </div>
          </div>

          {showVideoCall && (
            <div className="video-call-section">
              <VideoCall 
                partner={partner} 
                roomId={roomId} 
                onEndCall={() => setShowVideoCall(false)} 
              />
            </div>
          )}

          <div className="match-messages">
            <div className="match-start-message">
              🎉 You've been matched with {partner.nickname}!
            </div>
            {messages.map((msg, index) => (
              <div
                key={index}
                className={`match-message ${msg.isMine ? 'sent' : 'received'}`}
              >
                <p>{msg.text}</p>
                <span className="message-time">
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            ))}
            {isPartnerTyping && (
              <div className="typing-indicator">
                {partner.nickname} is typing...
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <form className="match-input" onSubmit={sendMessage}>
            <input
              type="text"
              value={inputMessage}
              onChange={handleTyping}
              placeholder="Type a message..."
            />
            <button type="submit" disabled={!inputMessage.trim()}>
              Send
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default RandomMatchPage;
